tasksRoutes.delete("/:id", requireAuth, async (c) => {
  const user2 = c.get("user");
  const taskId = c.req.param("id");
  const task = await db3.query.tasks.findFirst({ where: eq(tasks.id, taskId) });
  if (!task)
    return c.json({ error: "Task not found" }, 404);
  if (!await verifyProjectAccess(user2.id, task.projectId)) {
    return c.json({ error: "Forbidden" }, 403);
  }
  await db3.delete(tasks).where(eq(tasks.id, taskId));
  return c.json({ message: "Task deleted" });
});

// src/routes/assets.ts
var import_client_s3 = __toESM(require_dist_cjs74());
var import_s3_request_presigner = __toESM(require_dist_cjs76());
var assetsRoutes = new Hono2;
var s3 = new import_client_s3.S3Client({ region: process.env.AWS_REGION ?? "eu-west-3" });
var bucket = process.env.S3_ASSETS_BUCKET ?? "";
async function verifyTaskAccess(userId, taskId) {
  const task = await db3.query.tasks.findFirst({ where: eq(tasks.id, taskId) });
  if (!task)
    return null;
  const project = await db3.query.projects.findFirst({
    where: eq(projects.id, task.projectId)
  });
  if (!project)
    return null;
  const member = await db3.query.teamMembers.findFirst({
    where: and(eq(teamMembers.teamId, project.teamId), eq(teamMembers.userId, userId))
  });
  return member ? task : null;
}
assetsRoutes.post("/upload-url", requireAuth, async (c) => {
  const user2 = c.get("user");
  const { taskId, filename } = await c.req.json();
  if (!taskId || !filename) {
    return c.json({ error: "taskId and filename required" }, 400);
  }
  if (!await verifyTaskAccess(user2.id, taskId)) {
    return c.json({ error: "Forbidden" }, 403);
  }
  const s3Key = `tasks/${taskId}/${Date.now()}-${filename}`;
  const url2 = await import_s3_request_presigner.getSignedUrl(s3, new import_client_s3.PutObjectCommand({ Bucket: bucket, Key: s3Key }), { expiresIn: 600 });
  const [asset] = await db3.insert(taskAssets).values({ taskId, s3Key, filename }).returning();
  return c.json({ uploadUrl: url2, asset }, 201);
});
assetsRoutes.get("/", requireAuth, async (c) => {
  const user2 = c.get("user");
  const taskId = c.req.query("taskId");
  if (!taskId) {
    return c.json({ error: "taskId query parameter required" }, 400);
  }
  if (!await verifyTaskAccess(user2.id, taskId)) {
    return c.json({ error: "Forbidden" }, 403);
  }
  const assets = await db3.query.taskAssets.findMany({
    where: eq(taskAssets.taskId, taskId)
  });
  const assetsWithUrls = await Promise.all(assets.map(async (asset) => {
    const url2 = await import_s3_request_presigner.getSignedUrl(s3, new import_client_s3.GetObjectCommand({ Bucket: bucket, Key: asset.s3Key }), { expiresIn: 3600 });
    return { ...asset, downloadUrl: url2 };
  }));
  return c.json({ assets: assetsWithUrls });
});
assetsRoutes.delete("/:id", requireAuth, async (c) => {
  const user2 = c.get("user");
  const assetId = c.req.param("id");
  const asset = await db3.query.taskAssets.findFirst({
    where: eq(taskAssets.id, assetId)
  });
  if (!asset) {
    return c.json({ error: "Asset not found" }, 404);
  }
  if (!await verifyTaskAccess(user2.id, asset.taskId)) {
    return c.json({ error: "Forbidden" }, 403);
  }
  await s3.send(new import_client_s3.DeleteObjectCommand({ Bucket: bucket, Key: asset.s3Key }));
  await db3.delete(taskAssets).where(eq(taskAssets.id, assetId));
  return c.json({ message: "Asset deleted" });
});

// src/routes/admin.ts
var adminRoutes = new Hono2;
adminRoutes.get("/stats", requireAdmin, async (c) => {
  const [teamCount] = await db3.select({ count: sql3`count(*)` }).from(teams);
  const [projectCount] = await db3.select({ count: sql3`count(*)` }).from(projects);
  const [taskCount] = await db3.select({ count: sql3`count(*)` }).from(tasks);
  const users = await auth.api.listUsers({
    query: { limit: 1 },
    headers: c.req.raw.headers
  });
  return c.json({
    stats: {
      users: users?.total ?? 0,
      teams: Number(teamCount.count),
      projects: Number(projectCount.count),
      tasks: Number(taskCount.count)
    }
  });
});
adminRoutes.get("/users", requireAdmin, async (c) => {
  const page = Number(c.req.query("page") ?? "1");
  const limit = Number(c.req.query("limit") ?? "50");
  const users = await auth.api.listUsers({
    query: { limit, offset: (page - 1) * limit },
    headers: c.req.raw.headers
  });
  return c.json({ users });
});

// src/index.ts
var app = new Hono2;
var rawOrigins = process.env.TRUSTED_ORIGINS ?? "http://localhost:3000";
app.use("*", cors({
  origin: rawOrigins === "*" ? (origin) => origin : rawOrigins.split(",").map((o) => o.trim()),
  credentials: true,
  allowHeaders: ["Content-Type", "Authorization"],
  allowMethods: ["GET", "POST", "PATCH", "DELETE", "OPTIONS"]
}));
app.use("*", logger());
app.on(["POST", "GET", "OPTIONS"], "/api/auth/**", async (c) => {
  const hasBody = c.req.method !== "GET" && c.req.method !== "HEAD";
  let body;
  if (hasBody && c.req.raw.body) {
    body = await c.req.arrayBuffer();
  }
  const req = new Request(c.req.url, {
    method: c.req.method,
    headers: c.req.raw.headers,
    body
  });
  try {
    return await auth.handler(req);
  } catch (err) {
    console.error("[auth] error:", err);
    throw err;
  }
});
app.route("/api/users", usersRoutes);
app.route("/api/teams", teamsRoutes);
app.route("/api/invitations", invitationsRoutes);
app.route("/api/projects", projectsRoutes);
app.route("/api/tasks", tasksRoutes);
app.route("/api/assets", assetsRoutes);
app.route("/api/admin", adminRoutes);
app.get("/api/health", (c) => c.json({ status: "ok" }));
app.onError((err, c) => {
  console.error("[app] error:", err);
  const allowOrigin = rawOrigins === "*" ? c.req.header("Origin") ?? "*" : rawOrigins.split(",").map((o) => o.trim())[0] ?? "*";
  return c.json({ error: "Internal Server Error" }, 500, {
    "Access-Control-Allow-Origin": allowOrigin,
    "Access-Control-Allow-Credentials": "true",
    "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type, Authorization"
  });
});
var STRIP_STAGE = /^\/(dev|prd)\//;
var honoHandler = handle(app);
var handler = async (event, context) => {
  const ev = event;
  const pathToCheck = ev.rawPath ?? ev.path;
  if (typeof pathToCheck === "string" && STRIP_STAGE.test(pathToCheck)) {
    const cleaned = pathToCheck.replace(STRIP_STAGE, "/");
    ev.path = cleaned;
    ev.rawPath = cleaned;
    const ctx = ev.requestContext;
    if (ctx) {
      ctx.path = cleaned;
      ctx.resourcePath = cleaned;
      const http = ctx.http;
      if (http)
        http.path = cleaned;
    }
  }
  return honoHandler(event, context);
};
if (!process.env.AWS_LAMBDA_FUNCTION_NAME) {
  const port = Number(process.env.PORT ?? 3001);
  const server = Bun.serve({
    port,
    fetch: app.fetch
  });
  console.log(`API server running on http://localhost:${server.port}`);
}
